export const checkId = 'cors';
export const name = 'CORS Configured';
export const appliesTo = ['deployable', 'server', 'framework'];

const CORS_PATTERNS = [
  /require\s*\(\s*['"][^'"]*cors['"]\s*\)/,
  /import\s+.*?['"][^'"]*cors['"]/,
  /from\s+['"][^'"]*cors['"]/,
  /access-control-allow-origin/i,
  /access-control-allow-methods/i,
  /access-control-allow-headers/i,
  /access-control-allow-credentials/i,
  /access-control-expose-headers/i,
  /access-control-max-age/i,
  /access-control-request/i,
  /cors\s*:\s*(true|\{)/i,
  /cors\s*\(/i,
  /enableCors/i,
  /allowedOrigins?/i,
  /allowOrigin/i,
  /corsOrigins?/i,
  /use\s*\(\s*cors/i,
  /register\s*\([^)]*cors/i,
  /corsHandler/i,
  /handleCors/i,
  /withCors/i,
  /setHeader\s*\(\s*['"]Access-Control/i,
  /headers\s*\(\s*\)\s*\{[^}]*access-control/i,
];

const SERVER_UNSCOPED = new Set([
  'express', 'fastify', 'koa', 'hono', 'restify', 'polka', 'connect',
  'http-server', 'serve-static', 'json-server', 'nitro', 'nitropack',
  'firebase-functions', 'aws-lambda', 'serverless-http'
]);

const META_UNSCOPED = new Set(['next', 'nuxt', 'astro', 'solid-start', 'gatsby']);

const TUTORIAL_RX = /\b(learn|tutorial|example|examples|starter|template|boilerplate|course|guide|workshop|playground|docs|documentation|showcase|demo|sample|cheatsheet)\b/i;

function basename(p) {
  const i = p.lastIndexOf('/');
  return i >= 0 ? p.slice(i + 1) : p;
}

function unscoped(name) {
  if (!name) return '';
  const idx = name.indexOf('/');
  return name[0] === '@' && idx > 0 ? name.slice(idx + 1) : name;
}

function unscopedKeys(depsObj) {
  if (!depsObj) return new Set();
  return new Set(Object.keys(depsObj).map(unscoped));
}

function hasAny(targetSet, keys) {
  for (const k of keys) if (targetSet.has(k)) return true;
  return false;
}

function isTestOrExamplePath(p) {
  return /(^|\/)(test|tests|__tests__|spec|example|examples|fixtures|fixture|mock|mocks|docs|playground|storybook|e2e|cypress|vitest|jest|node_modules|dist|build|coverage|\.tmp|\.next|out)\//i.test(p);
}

function isTutorialRepo(pj) {
  if (!pj) return false;
  const signals = [pj.name, pj.description, ...(pj.keywords || [])].filter(Boolean);
  return signals.some(s => TUTORIAL_RX.test(s));
}

function isLibraryOrTool(pj, tree) {
  if (!pj) return false;
  const scripts = pj.scripts || {};
  const deps = { ...(pj.dependencies || {}), ...(pj.devDependencies || {}) };
  const keys = unscopedKeys(deps);

  if (pj.bin) return true;

  if (pj.peerDependencies && Object.keys(pj.peerDependencies).length > 0) {
    if (!scripts.start && !scripts.serve && !scripts['start:prod'] && !hasAny(SERVER_UNSCOPED, keys)) {
      return true;
    }
  }

  const toolish = new Set(['bundler', 'build-tool', 'compiler', 'transpiler', 'linter', 'formatter', 'cli', 'command-line', 'scaffold', 'generator', 'test-runner', 'testing', 'package-manager', 'monorepo', 'workspace', 'plugin', 'preset', 'toolkit']);
  const keywords = (pj.keywords || []).map(k => k.toLowerCase());
  if (keywords.some(k => toolish.has(k))) {
    if (!scripts.start && !scripts.serve && !hasAny(SERVER_UNSCOPED, keys)) return true;
  }

  const isPrivate = pj.private === true;
  const hasWorkspaces = !!(pj.workspaces || tree.some(p => basename(p) === 'pnpm-workspace.yaml' || basename(p) === 'turbo.json'));
  const hasPackagesDir = tree.some(p => /^packages\/[^/]+\//.test(p));
  const hasAppsDir = tree.some(p => /^(apps|services|sites)\/[^/]+\//.test(p));

  if (isPrivate && hasWorkspaces && hasPackagesDir && !hasAppsDir && !scripts.start && !scripts.serve) {
    return true;
  }

  if ((pj.main || pj.module || pj.exports || pj.types || pj.typings) && !scripts.start && !scripts.serve && !hasAny(SERVER_UNSCOPED, keys)) {
    const devScript = scripts.dev || '';
    if (!/\bserve\b/.test(devScript) && !/\bserver\b/.test(devScript)) return true;
  }

  return false;
}

function hasBackendContext(tree) {
  const apiRx = /\/(api|pages\/api|app\/api|server\/api|src\/app\/api|src\/pages\/api|src\/routes|routes|server\/routes|controllers|handlers|middleware|plugins)\/[^/]+\.(js|ts|mjs|cjs|jsx|tsx|mts|cts)$/;
  const entryRx = /^(server|app|listen|main|worker)\.(js|ts|mjs|cjs|jsx|tsx|mts|cts)$/;
  const srcEntryRx = /^src\/(server|app|listen|main|worker)\.(js|ts|mjs|cjs|jsx|tsx|mts|cts)$/;

  for (const p of tree) {
    if (isTestOrExamplePath(p)) continue;
    if (apiRx.test(p) || entryRx.test(basename(p)) || srcEntryRx.test(p)) return true;
  }
  return false;
}

function isStaticOrSsrOnly(pj, tree) {
  const hasFrontend = tree.some(p => /\.(jsx|tsx|vue|svelte|html|css|scss|astro)$/.test(p));
  if (!hasFrontend) return false;
  if (hasBackendContext(tree)) return false;

  const scripts = pj?.scripts || {};
  const deps = { ...(pj?.dependencies || {}), ...(pj?.devDependencies || {}) };
  const keys = unscopedKeys(deps);

  if (hasAny(META_UNSCOPED, keys)) return true;
  if (!hasAny(SERVER_UNSCOPED, keys) && !scripts.start && !scripts.serve && !scripts['start:prod']) return true;

  return false;
}

export async function check(context) {
  const { tree, files, packageJson, repoType } = context;

  try {
    if (repoType === 'empty' || tree.length === 0) {
      return { checkId, status: 'not-applicable', confidence: 'high', message: 'Empty repo — CORS not applicable', findings: [] };
    }

    if (isTutorialRepo(packageJson)) {
      return { checkId, status: 'not-applicable', confidence: 'high', message: 'Tutorial or example repo — CORS not applicable', findings: [] };
    }

    if (isLibraryOrTool(packageJson, tree)) {
      return { checkId, status: 'not-applicable', confidence: 'high', message: 'Library, tool, or framework source — CORS not applicable', findings: [] };
    }

    if (isStaticOrSsrOnly(packageJson, tree)) {
      return { checkId, status: 'not-applicable', confidence: 'high', message: 'Static or SSR-only site with no API endpoints — CORS not applicable', findings: [] };
    }

    const rootDeps = { ...(packageJson?.dependencies || {}), ...(packageJson?.devDependencies || {}), ...(packageJson?.peerDependencies || {}) };
    const rootKeys = unscopedKeys(rootDeps);
    if (rootKeys.has('cors') || Object.keys(rootDeps).some(k => /\bcors\b/i.test(unscoped(k)))) {
      return { checkId, status: 'pass', confidence: 'high', message: 'CORS dependency found', findings: [] };
    }

    const isMonorepo = !!(packageJson?.workspaces || tree.some(p => basename(p) === 'pnpm-workspace.yaml' || basename(p) === 'turbo.json'));
    if (isMonorepo) {
      const subPkgPaths = tree
        .filter(p => /(^|\/)package\.json$/.test(p) && !/node_modules/.test(p) && p !== 'package.json')
        .slice(0, 30);

      for (const pkgPath of subPkgPaths) {
        const content = await files.get(pkgPath);
        if (!content) continue;
        try {
          const subPkg = JSON.parse(content);
          const subDeps = { ...(subPkg.dependencies || {}), ...(subPkg.devDependencies || {}) };
          if (unscopedKeys(subDeps).has('cors') || Object.keys(subDeps).some(k => /\bcors\b/i.test(unscoped(k)))) {
            return { checkId, status: 'pass', confidence: 'high', message: `CORS dependency found in ${pkgPath}`, findings: [{ file: pkgPath, issue: 'CORS dependency detected' }] };
          }
        } catch {
          // skip invalid JSON
        }
      }
    }

    const candidates = [];
    for (const p of tree) {
      if (!/\.(js|ts|mjs|cjs|jsx|tsx|mts|cts)$/.test(p)) continue;
      if (isTestOrExamplePath(p)) continue;

      let score = 0;
      const b = basename(p);

      if (/\.config\.(js|ts|mjs|cjs)$/.test(b)) score += 100;
      if (/^(server|app|listen|main|worker)\.(js|ts|mjs|cjs|jsx|tsx|mts|cts)$/.test(b)) score += 80;
      if (/^src\/(server|app|listen|main|worker)\.(js|ts|mjs|cjs|jsx|tsx|mts|cts)$/.test(p)) score += 75;
      if (/\/(api|pages\/api|app\/api|server\/api|src\/app\/api|src\/pages\/api|routes|server\/routes|controllers|handlers|middleware|plugins)\/[^/]+\.(js|ts|mjs|cjs|jsx|tsx|mts|cts)$/.test(p)) score += 70;
      if (/\.route\.(js|ts|mjs|cjs|jsx|tsx|mts|cts)$/.test(p)) score += 50;
      if (/^(index|app)\.(js|ts|mjs|cjs|jsx|tsx|mts|cts)$/.test(b)) score += 40;
      if (/^src\/(index|app)\.(js|ts|mjs|cjs|jsx|tsx|mts|cts)$/.test(p)) score += 35;

      if (score > 0) candidates.push({ path: p, score });
    }

    candidates.sort((a, b) => b.score - a.score);
    const scanPaths = candidates.slice(0, 25);

    for (const { path: filePath } of scanPaths) {
      const content = await files.get(filePath);
      if (!content) continue;

      for (const pattern of CORS_PATTERNS) {
        if (pattern.test(content)) {
          return { checkId, status: 'pass', confidence: 'high', message: `CORS configuration found in ${filePath}`, findings: [{ file: filePath, issue: 'CORS detected' }] };
        }
      }

      if (/\.config\.(js|ts|mjs|cjs)$/.test(filePath) && /headers/i.test(content) && /access-control/i.test(content)) {
        return { checkId, status: 'pass', confidence: 'high', message: `CORS headers configured in ${filePath}`, findings: [{ file: filePath, issue: 'CORS headers detected' }] };
      }
    }

    if (hasBackendContext(tree)) {
      return { checkId, status: 'fail', confidence: 'medium', message: 'API routes or server entry detected, but no CORS configuration found', findings: [{ file: 'unknown', issue: 'Server context without CORS' }] };
    }

    const scripts = packageJson?.scripts || {};
    const deps = { ...(packageJson?.dependencies || {}), ...(packageJson?.devDependencies || {}) };
    if (hasAny(SERVER_UNSCOPED, unscopedKeys(deps)) || scripts.start || scripts.serve || scripts['start:prod']) {
      return { checkId, status: 'fail', confidence: 'medium', message: 'Server runtime detected, but no CORS configuration found', findings: [{ file: 'unknown', issue: 'Server runtime without CORS' }] };
    }

    return { checkId, status: 'check-it', confidence: 'low', message: 'Unable to determine if CORS is needed — no clear server or API patterns detected', findings: [{ file: 'unknown', issue: 'Ambiguous repo structure' }] };
  } catch (err) {
    console.error(`[${checkId}] Unexpected error:`, err);
    return { checkId, status: 'check-it', confidence: 'low', message: `Error during CORS check: ${err.message}`, findings: [{ file: 'unknown', issue: `Error: ${err.message}` }] };
  }
}
